INSERT INTO Inquiry_attachment ( attach_id, inquiry_id, file_name, file_path, file_size, file_type, created_at ) SELECT Inquiry_attachment_seq.nextval, A.* FROM (
SELECT #{item.inquiry_id}, #{item.file_name}, #{item.file_path}, #{item.file_size}, #{item.file_type}, SYSDATE FROM dual
) A
